func newReportDedupeCmd(flags *rootFlags) *cobra.Command {
	var title, asset, cwe string
	var limit int
	cmd := &cobra.Command{
		Use:         "dedupe",
		Short:       "Search local data for likely duplicate reports",
		Long:        "Search the local SQLite store for reports and hacktivity entries that overlap a candidate title, asset, or CWE.",
		Example:     "  yeswehack-pp-cli report dedupe --title 'Stored XSS' --asset app.example.com --cwe CWE-79 --json",
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) > 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}
			query := strings.TrimSpace(strings.Join([]string{title, asset, cwe}, " "))
			if query == "" {
				return cmd.Help()
			}
			db, err := openResearchStore()
			if err != nil {
				return err
			}
			defer db.Close()
			rows, err := reportDedupeCollisions(db, title, asset, cwe, limit)
			if err != nil {
				return err
			}
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				if err := printJSONFiltered(cmd.OutOrStdout(), rows, flags); err != nil {
					return err
				}
			} else {
				for _, row := range rows {
					fmt.Fprintf(cmd.OutOrStdout(), "%.2f\t%s\t%s\n", row["score"], row["program"], row["title"])
				}
			}
			if len(rows) > 0 {
				if score, ok := rows[0]["score"].(float64); ok && score >= 0.8 {
					return &cliError{code: 2, err: fmt.Errorf("likely duplicate found")}
				}
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&title, "title", "", "Candidate report title")
	cmd.Flags().StringVar(&asset, "asset", "", "Candidate affected asset")
	cmd.Flags().StringVar(&cwe, "cwe", "", "Candidate CWE")
	cmd.Flags().IntVar(&limit, "limit", 10, "Maximum results")
	cmd.Flags().BoolVar(&flags.asJSON, "json", flags.asJSON, "Output as JSON")
	return cmd
}
